from elasticsearch import Elasticsearch

# Connect to Elasticsearch cluster
es = Elasticsearch('localhost:9200')

# Index document
def index_document(index, doc_type, data):
    es.index(index=index, doc_type=doc_type, body=data)

# Search query
def search_query(index, query):
    result = es.search(index=index, body={"query": {"match": {"message": query}}})
    return result['hits']['hits']

# Log aggregation
def log_aggregation(index, aggregation_field):
    result = es.search(index=index, body={"aggs": {aggregation_field: {"terms": {"field": aggregation_field}}}})
    return result['aggregations'][aggregation_field]['buckets']

